import{c as i,S as h,j as t,m as a}from"./chunks/framework.8aa1YH_s.js";const m=JSON.parse('{"title":"Thống kê & Báo cáo","description":"","frontmatter":{},"headers":[],"relativePath":"admin/thong-ke.md","filePath":"admin/thong-ke.md","lastUpdated":0}'),l={name:"admin/thong-ke.md"};function o(c,n,e,g,r,s){return h(),t("div",null,[...n[0]||(n[0]=[a('<h1 id="thong-ke-bao-cao" tabindex="-1">Thống kê &amp; Báo cáo <a class="header-anchor" href="#thong-ke-bao-cao" aria-label="Permalink to “Thống kê &amp; Báo cáo”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/statistic/...</code></p><p>Mục <strong>Thống kê</strong> cung cấp 4 báo cáo chi tiết, mỗi báo cáo có thể lọc theo thời gian, theo khóa học, theo giáo viên, theo loại chương trình…</p><h2 id="_1-thong-ke-khoa-hoc" tabindex="-1">1. Thống kê Khóa học <a class="header-anchor" href="#_1-thong-ke-khoa-hoc" aria-label="Permalink to “1. Thống kê Khóa học”">​</a></h2><p><code>https://lamsonedutech.vn/admin/statistic/course</code></p><p><strong>Bảng số liệu hiển thị:</strong></p><ul><li>Tên khóa học, giáo viên phụ trách, loại chương trình</li><li>Số học viên đã đăng ký</li><li>Số học viên đang học (có hoạt động trong 30 ngày)</li><li>Doanh thu từ khóa</li><li>Số bài giảng / chuyên đề đã hoàn thiện</li></ul><p><strong>Bộ lọc:</strong></p><ul><li>Khoảng thời gian (ngày bắt đầu - kết thúc)</li><li>Loại chương trình (ĐGNL, ĐGTD, TNTHPT, ...)</li><li>Trạng thái khóa (Đang công khai / Đã ẩn)</li></ul><p><strong>Xuất file:</strong> Bấm nút <strong>Excel</strong> để tải báo cáo về máy.</p><h2 id="_2-thong-ke-giao-vien" tabindex="-1">2. Thống kê Giáo viên <a class="header-anchor" href="#_2-thong-ke-giao-vien" aria-label="Permalink to “2. Thống kê Giáo viên”">​</a></h2><p><code>https://lamsonedutech.vn/admin/statistic/teacher</code></p><p><strong>Bảng số liệu:</strong></p><ul><li>Tên giáo viên, số khóa học phụ trách</li><li>Số học viên đang dạy</li><li>Số đề thi / bài giảng đã tạo</li><li>Doanh thu từ các khóa của giáo viên này (nếu có cơ chế chia)</li><li>Phản hồi / đánh giá trung bình từ học viên</li></ul><p><strong>Sử dụng để:</strong></p><ul><li>Đánh giá hiệu quả của từng giáo viên.</li><li>Tính chiết khấu / hoa hồng cho giáo viên cộng tác.</li></ul><h2 id="_3-thong-ke-hoc-vien" tabindex="-1">3. Thống kê Học viên <a class="header-anchor" href="#_3-thong-ke-hoc-vien" aria-label="Permalink to “3. Thống kê Học viên”">​</a></h2><p><code>https://lamsonedutech.vn/admin/statistic/student</code></p><p><strong>Bảng số liệu:</strong></p><ul><li>Họ tên, số điện thoại, email</li><li>Ngày đăng ký</li><li>Số khóa học đã mua</li><li>Tổng số tiền đã chi</li><li>Số bài thi đã làm, điểm trung bình</li><li>Trạng thái hoạt động (Active / Inactive)</li></ul><p><strong>Bộ lọc:</strong></p><ul><li>Khoảng ngày đăng ký</li><li>Loại chương trình đã mua</li><li>Tỉnh / thành phố</li><li>Khối lớp (10, 11, 12 nếu có)</li></ul><p><strong>Sử dụng để:</strong></p><ul><li>Lọc học viên VIP (chi nhiều) để chăm sóc.</li><li>Lọc học viên không hoạt động → gửi email/SMS nhắc nhở.</li></ul><h2 id="_4-thong-ke-ket-qua-thi" tabindex="-1">4. Thống kê Kết quả thi <a class="header-anchor" href="#_4-thong-ke-ket-qua-thi" aria-label="Permalink to “4. Thống kê Kết quả thi”">​</a></h2><p><code>https://lamsonedutech.vn/admin/statistic/exam</code></p><p><strong>Bảng số liệu:</strong></p><ul><li>Tên học viên, tên đề thi, ngày làm</li><li>Loại bài (ĐGNL / ĐGTD / THPT / Kiểm tra đầu vào / Đề ôn chuyên đề)</li><li>Tổng điểm, điểm từng phần</li><li>Thời gian làm bài</li><li>Số lần làm lại (nếu đề cho phép)</li></ul><p><strong>Bộ lọc:</strong></p><ul><li>Khoảng thời gian</li><li>Tên đề thi</li><li>Khóa học</li><li>Học viên</li><li>Mức điểm (vd: ≥ 100 điểm ĐGNL)</li></ul><p><strong>Sử dụng để:</strong></p><ul><li>Xác định những đề có điểm trung bình quá thấp / quá cao (có thể cần điều chỉnh độ khó).</li><li>Báo cáo chất lượng đầu ra cho phụ huynh / nhà trường.</li><li>Lập bảng vinh danh học viên xuất sắc.</li></ul><h2 id="thao-tac-chung" tabindex="-1">Thao tác chung <a class="header-anchor" href="#thao-tac-chung" aria-label="Permalink to “Thao tác chung”">​</a></h2><h3 id="loc-nhanh" tabindex="-1">Lọc nhanh <a class="header-anchor" href="#loc-nhanh" aria-label="Permalink to “Lọc nhanh”">​</a></h3><ul><li>Trên đầu mỗi bảng có thanh <strong>Bộ lọc</strong>. Chọn xong bấm <strong>Áp dụng</strong>.</li><li>Bấm <strong>Đặt lại</strong> để xóa tất cả bộ lọc.</li></ul><h3 id="sap-xep" tabindex="-1">Sắp xếp <a class="header-anchor" href="#sap-xep" aria-label="Permalink to “Sắp xếp”">​</a></h3><ul><li>Bấm vào tiêu đề cột để sắp xếp tăng/giảm.</li></ul><h3 id="tim-kiem" tabindex="-1">Tìm kiếm <a class="header-anchor" href="#tim-kiem" aria-label="Permalink to “Tìm kiếm”">​</a></h3><ul><li>Ô <strong>Tìm kiếm</strong> ở góc trên cho phép tìm theo tên, mã, số điện thoại…</li></ul><h3 id="phan-trang" tabindex="-1">Phân trang <a class="header-anchor" href="#phan-trang" aria-label="Permalink to “Phân trang”">​</a></h3><ul><li>Mặc định hiển thị 10 dòng/trang. Có thể đổi 50/100/500/1000 ở góc dưới phải.</li></ul><h3 id="xuat-excel-in-bao-cao" tabindex="-1">Xuất Excel / In báo cáo <a class="header-anchor" href="#xuat-excel-in-bao-cao" aria-label="Permalink to “Xuất Excel / In báo cáo”">​</a></h3><ul><li>Nút <strong>Xuất Excel</strong> xuất toàn bộ dữ liệu <strong>đã lọc</strong>.</li><li>Nút <strong>In</strong> in trang hiện tại theo format chuẩn báo cáo.</li></ul><h2 id="meo-đoc-bao-cao" tabindex="-1">Mẹo đọc báo cáo <a class="header-anchor" href="#meo-đoc-bao-cao" aria-label="Permalink to “Mẹo đọc báo cáo”">​</a></h2><ul><li><strong>Nhìn theo xu hướng</strong> (so với tuần / tháng trước) thay vì chỉ một con số.</li><li><strong>Đối chiếu chéo:</strong> doanh thu giảm có thể không phải do giáo viên kém, mà do thay đổi giá / khuyến mãi → xem cả <a href="./khuyen-mai">Khuyến mãi</a>.</li><li><strong>Đừng chỉ xem trung bình:</strong> thường có &quot;phân hóa hai đỉnh&quot; (giỏi - yếu rõ rệt), nên xem thêm phân phối điểm.</li></ul>',45)])])}const d=i(l,[["render",o]]);export{m as __pageData,d as default};
